public class UDACAccessibilityService extends AccessibilityService {

    public static final String ACTION_UDAC_EVENT = "org.dimensionalcortex.UDAC_EVENT";
    private static final String TAG = "UDACService";

    @Override
    public void onAccessibilityEvent(AccessibilityEvent event) {
        if (event == null) return;

        if (event.getText() == null || event.getText().isEmpty()) {
            return;
        }

        CharSequence text = event.getText().get(0);
        if (text == null || text.length() == 0) {
            return;
        }

        Intent intent = new Intent();
        intent.setAction(ACTION_UDAC_EVENT);
        intent.putExtra("captured_text", text.toString());
        sendBroadcast(intent);

        Log.d(TAG, "Broadcasted UDAC text: " + text);
    }

    @Override
    public void onInterrupt() {
        // No-op
    }
}
