## 1. `background.js` – Real service worker, real state

This manages:
- Global “capture on/off” state in `chrome.storage`
- User tier in `chrome.storage` (for future use)
- Broadcasts toggle messages to all matching tabs so your existing `content_script.js` keeps working

```js
// background.js - Dimensional Cortex service worker

const DEFAULT_STATE = {
  captureEnabled: false,
  userTier: 'free', // free | pro | lifetime | enterprise (future-proofed)
};

// Initialize default state on install
chrome.runtime.onInstalled.addListener(() => {
  chrome.storage.sync.get(['captureEnabled', 'userTier'], (data) => {
    const newState = {
      captureEnabled:
        typeof data.captureEnabled === 'boolean'
          ? data.captureEnabled
          : DEFAULT_STATE.captureEnabled,
      userTier: data.userTier || DEFAULT_STATE.userTier,
    };
    chrome.storage.sync.set(newState);
  });
});

// Helper: send toggle message to all relevant tabs
function broadcastCaptureState(enabled) {
  const matches = [
    '*://chat.openai.com/*',
    '*://claude.ai/*',
    '*://www.perplexity.ai/*',
  ];
  chrome.tabs.query({ url: matches }, (tabs) => {
    tabs.forEach((tab) => {
      chrome.tabs.sendMessage(
        tab.id,
        { action: 'toggle', enabled },
        () => {
          // ignore errors from tabs without the content script
          void chrome.runtime.lastError;
        }
      );
    });
  });
}

// Handle messages from popup / content scripts
chrome.runtime.onMessage.addListener((message, sender, sendResponse) => {
  if (message && message.type === 'GET_STATE') {
    chrome.storage.sync.get(['captureEnabled', 'userTier'], (data) => {
      sendResponse({
        captureEnabled:
          typeof data.captureEnabled === 'boolean'
            ? data.captureEnabled
            : DEFAULT_STATE.captureEnabled,
        userTier: data.userTier || DEFAULT_STATE.userTier,
      });
    });
    return true; // async response
  }

  if (message && message.type === 'SET_CAPTURE_ENABLED') {
    const enabled = !!message.enabled;
    chrome.storage.sync.set({ captureEnabled: enabled }, () => {
      broadcastCaptureState(enabled);
      sendResponse({ ok: true, captureEnabled: enabled });
    });
    return true; // async response
  }

  if (message && message.type === 'SET_USER_TIER') {
    const allowed = ['free', 'pro', 'lifetime', 'enterprise'];
    const tier = allowed.includes(message.tier) ? message.tier : 'free';
    chrome.storage.sync.set({ userTier: tier }, () => {
      sendResponse({ ok: true, userTier: tier });
    });
    return true;
  }

  return false;
});

// Optional: clicking the extension icon toggles capture without popup
