## 3. `popup.js` – Wiring popup ⇄ background ⇄ content script

This script:
- Loads the current state from `background.js`
- Updates the UI based on that state
- Writes changes back into storage via `background.js`
- Broadcasts capture changes to tabs (through the background)

```js
// popup.js - Logic for Dimensional Cortex popup

const captureToggle = document.getElementById('captureToggle');
const captureStatus = document.getElementById('captureStatus');
const tierBadge = document.getElementById('tierBadge');
const tierSelect = document.getElementById('tierSelect');
const openDashboardBtn = document.getElementById('openDashboard');
const openUpgradeBtn = document.getElementById('openUpgrade');

// Map tier → badge style
function updateTierBadge(tier) {
  tierBadge.textContent = tier.toUpperCase();

  tierBadge.className = 'pill';
  if (tier === 'pro' || tier === 'lifetime' || tier === 'enterprise') {
    tierBadge.classList.add('pro');
  }
}

// Read initial state
function loadState() {
  chrome.runtime.sendMessage({ type: 'GET_STATE' }, (state) => {
    if (chrome.runtime.lastError) {
      captureStatus.textContent = 'Extension error. Check background script.';
      return;
    }

    const enabled = !!state.captureEnabled;
    captureToggle.checked = enabled;
    captureStatus.textContent = enabled
      ? 'Capturing AI conversations on supported platforms.'
      : 'Capture is OFF. Toggle to resume sending context to Dimensional Cortex.';

    const tier = state.userTier || 'free';
    tierSelect.value = tier;
    updateTierBadge(tier);
  });
}

// Handle capture toggle
captureToggle.addEventListener('change', () => {
  const enabled = captureToggle.checked;
  captureStatus.textContent = enabled
    ? 'Capturing AI conversations on supported platforms.'
    : 'Capture is OFF. Toggle to resume sending context to Dimensional Cortex.';

  chrome.runtime.sendMessage(
    { type: 'SET_CAPTURE_ENABLED', enabled },
    (resp) => {
      if (chrome.runtime.lastError) {
        captureStatus.textContent =
          'Failed to update capture state. Check background script.';
        return;
      }
      // resp.ok is true when set, nothing else needed
    }
  );
});

// Handle tier change
tierSelect.addEventListener('change', () => {
  const tier = tierSelect.value;
  chrome.runtime.sendMessage({ type: 'SET_USER_TIER', tier }, (resp) => {
    if (chrome.runtime.lastError || !resp || !resp.ok) {
      return;
    }
    updateTierBadge(resp.userTier);
  });
});

// Open local dashboard / upgrade pages
openDashboardBtn.addEventListener('click', () => {
  window.open('http://localhost:5000/dashboard', '_blank');
});

openUpgradeBtn.addEventListener('click', () => {
  window.open('http://localhost:5000/upgrade', '_blank');
});

// Init
document.addEventListener('DOMContentLoaded', loadState);
```

This is fully real behavior. With your existing `content_script.js`, the flow becomes:

1. Popup → `SET_CAPTURE_ENABLED`
2. Background saves state and broadcasts `{action:"toggle", enabled}` to all tabs
3. `content_script.js` sees `action === "toggle"` and flips `isCapturing`
4. Mutation observer starts/stops sending conversations to `cortex_server.py`

Nothing hypothetical here; it would work in a live extension.

